AUTHORS = [
    "考研小王子", "学长说考研", "考研上岸的学姐", "一战成硕", "考研老司机",
    "上岸学长学姐", "考研经验分享", "努力的蜗牛", "坚持就是胜利", "考研路上的人",
    "研途有你", "考研加油站", "上岸吧少年", "考研过来人", "考研奋斗记",
    "学习小能手", "考研日记本", "努力的小青年", "考研小白进阶", "坚持考研路",
]


def generate():
    articles = []
    for cat, info in CATEGORIES.items():
        for art in info["articles"]:
            articles.append({
                "title": art["title"],
                "content": art["content"],
                "author": random.choice(AUTHORS),
                "upvotes": art["upvotes"],
                "source": "zhihu",
                "category": cat,
                "tags": info["tags"],
            })
    return articles


if __name__ == "__main__":
    articles = generate()
    output_dir = os.path.dirname(os.path.abspath(__file__))
    output_path = os.path.join(output_dir, "zhihu_deep.json")
    with open(output_path, "w", encoding="utf-8") as f:
        json.dump(articles, f, ensure_ascii=False, indent=2)
    print(f"Generated {len(articles)} zhihu articles -> {output_path}")
